Iteratively attempt to insert each ship into the cheapest feasible existing assign using a greedy cost‑delta evaluation with full rollback; if none is feasible, create a new assign for that ship.}
func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
    for jj := range oris {
        bestAssignIdx := -1
        bestCostDelta := 1e18
        shipID := total_ship + jj
        // Try inserting into existing assigns first
        for ii := 0; ii < dispatch.AssignsLen; ii++ {
            // Save current state
            savedCost := dispatch.Assigns[ii].Cost
            savedStationCurrent := dispatch.Assigns[ii].StationCurrent
            // Try insertion
            ok := dispatch.Assigns[ii].AddShip(shipID, oris[jj], dess[jj])
            if !ok {
                continue
            }
            dispatch.Assigns[ii].GenRoute()
            if dispatch.Assigns[ii].Cost < 0 {
                // Infeasible, rollback
                dispatch.Assigns[ii].RemoveShip(shipID)
                dispatch.Assigns[ii].GenRoute()
                // Restore original fields (GenRoute may reset them; ensure consistency via RemoveShip+GenRoute)
                continue
            }
            costDelta := dispatch.Assigns[ii].Cost - savedCost
            if costDelta < bestCostDelta {
                bestCostDelta = costDelta
                bestAssignIdx = ii
            }
            // Rollback trial insertion
            dispatch.Assigns[ii].RemoveShip(shipID)
            dispatch.Assigns[ii].GenRoute()
            // Ensure state restored (GenRoute after removal restores feasibility)
        }
        // Commit best insertion if found
        if bestAssignIdx != -1 {
            dispatch.Assigns[bestAssignIdx].AddShip(shipID, oris[jj], dess[jj])
            dispatch.Assigns[bestAssignIdx].GenRoute()
            continue
        }
        // Fallback: try empty/new assign slots up to MAXASSIGNS
        placed := false
        for ii := 0; ii < MAXASSIGNS; ii++ {
            // Check if this slot is already used (within AssignsLen) or is a fresh slot
            if ii < dispatch.AssignsLen {
                // Already considered above; skip to avoid double‑trial
                continue
            }
            // Initialize fresh assign implicitly via zero value; AddShip will set up initial route
            ok := dispatch.Assigns[ii].AddShip(shipID, oris[jj], dess[jj])
            if !ok {
                continue
            }
            dispatch.Assigns[ii].GenRoute()
            if dispatch.Assigns[ii].Cost >= 0 {
                // Successfully created new assign
                if ii >= dispatch.AssignsLen {
                    dispatch.AssignsLen = ii + 1
                }
                placed = true
                break
            } else {
                // Should not happen for a fresh assign, but rollback anyway
                dispatch.Assigns[ii].RemoveShip(shipID)
                dispatch.Assigns[ii].GenRoute()
            }
        }
        // Safety: if still not placed, force creation at AssignsLen (must succeed per problem guarantee)
        if !placed {
            idx := dispatch.AssignsLen
            if idx < MAXASSIGNS {
                dispatch.Assigns[idx].AddShip(shipID, oris[jj], dess[jj])
                dispatch.Assigns[idx].GenRoute()
                dispatch.AssignsLen++
            }
        }
    }
    dispatch.RenewnTotalCost()
    return dispatch

